using System.Net;using System.Net.Http.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Bad case: Try to update EHR record with invalid data (null diagnosis, etc.)/// Expected: 400 Bad Request or validation error/// </summary>public class EhrServiceTests_UpdateEhrRecord_WithInvalidData_ShouldReturnBadRequest : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task UpdateEhrRecord_WithInvalidData_ShouldReturnBadRequest()    {        await AuthenticateAsDoctorAsync(EhrClient);        // Create an EHR first        var createRequest = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Test",                 treatment = "Test",                 notes = "Test"             }         };        var createResponse = await PostAsJsonWithRetryAsync(EhrClient, ApiEndpoints.Ehr.CreateRecord, createRequest);        var createJson = await ReadJsonResponseAsync(createResponse);                if (!createJson.TryGetProperty("ehrId", out var ehrIdElement))            return; // Skip if creation fails        var ehrId = Guid.Parse(ehrIdElement.GetString()!);        // Try to update with null data (invalid)        var invalidUpdateRequest = new { };        var updateResponse = await PutAsJsonWithRetryAsync(            EhrClient,             ApiEndpoints.Ehr.UpdateRecord(ehrId),             invalidUpdateRequest);        // Should reject invalid data        Assert.True(            updateResponse.StatusCode == HttpStatusCode.BadRequest ||             updateResponse.StatusCode == HttpStatusCode.UnprocessableEntity,            $"Expected 400 or 422, got {updateResponse.StatusCode}");    }}